def range_summary(nums):
    if not nums: return ''  # handle empty list edge case
    nums = sorted(set(nums))  # get distinct, sorted numbers
    ranges = []
    start = end = nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start != end:
                ranges.append(f'{start}-{end}' if start < end else f'{start}')
            else:
                ranges.append(str(start))
            start = end = num

    if start != end:
        ranges.append(f'{start}-{end}' if start < end else f'{start}')
    else:
        ranges.append(str(start))

    return ','.join(ranges)
